def _parse_timestamp(value: str) -> datetime:
    raw = value.strip()
    if raw.endswith("Z"):
        raw = raw[:-1] + "+00:00"
    dt = datetime.fromisoformat(raw)
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)
    return dt.astimezone(timezone.utc)


def _to_julday(dt_utc: datetime) -> float:
    return swe.julday(
        dt_utc.year,
        dt_utc.month,
        dt_utc.day,
        dt_utc.hour + dt_utc.minute / 60 + dt_utc.second / 3600 + dt_utc.microsecond / 3_600_000_000,
    )


def _resolve_timezone(lat: float, lon: float) -> str | None:
    if not _TZ_FINDER:
        return None
    try:
        return _TZ_FINDER.timezone_at(lat=lat, lng=lon)
    except Exception:
        return None


def _format_local_timestamp(dt_utc: datetime, tz_name: str | None) -> str | None:
    if not tz_name:
        return None
    try:
        return dt_utc.astimezone(ZoneInfo(tz_name)).isoformat()
    except Exception:
        return None


def _round_floats(value, ndigits: int = 2):
    if isinstance(value, float):
        return round(value, ndigits)
    if isinstance(value, list):
        return [_round_floats(item, ndigits) for item in value]
    if isinstance(value, dict):
        return {key: _round_floats(item, ndigits) for key, item in value.items()}
    return value


def round_payload(payload: dict, ndigits: int = 2) -> dict:
    return _round_floats(payload, ndigits)


def _default_aspect_config() -> tuple[str, List[float], Dict[float, float], Dict[float, str]]:
    return ASPECT_SET, ASPECT_ANGLES, ASPECT_ORBS, ASPECT_CLASSES


def _normalize_deg(value: float) -> float:
    return value % 360.0


def _normalize_signed_deg(value: float) -> float:
    return ((value + 180.0) % 360.0) - 180.0


def _angular_distance(a: float, b: float) -> float:
    diff = abs(a - b) % 360.0
    return min(diff, 360.0 - diff)


def _sign_info(lon: float) -> Tuple[str, float]:
    index = int(lon // 30)
    return SIGNS[index], lon % 30.0


def _body_like_from_lon_lat(lon: float, lat: float, speed: float, house: int) -> dict:
    lon = _normalize_deg(lon)
    sign, deg_in_sign = _sign_info(lon)
    return {
        "lon": lon,
        "lat": lat,
        "speed": speed,
        "retrograde": speed < 0,
        "sign": sign,
        "deg_in_sign": deg_in_sign,
        "house": house,
    }


def _stub_body(house: int = 1) -> dict:
    return _body_like_from_lon_lat(0.0, 0.0, 0.0, house)


def _angle_payload(lon: float) -> dict:
    lon = _normalize_deg(lon)
    sign, deg_in_sign = _sign_info(lon)
    return {
        "lon": lon,
        "sign": sign,
        "deg_in_sign": deg_in_sign,
    }


def _resolve_ephe_path() -> Path | None:
    env_path = os.getenv("SE_EPHE_PATH")
    if env_path:
        env_candidate = Path(env_path)
        if env_candidate.exists():
            return env_candidate

    package_path = Path(__file__).resolve().parents[2] / "ephe"
    if package_path.exists():
        return package_path

    local_path = Path(__file__).resolve().parents[3] / "_local" / "ephe"
    if local_path.exists():
        return local_path

    if env_path:
        return Path(env_path)

    return None


def _ensure_ephe_path() -> Path:
    if not SWE_AVAILABLE:
        raise RuntimeError("swisseph_unavailable")

    ephe_path = _resolve_ephe_path()
    if not ephe_path:
        raise RuntimeError("SE_EPHE_PATH not set and default ephe path missing")
    if not ephe_path.exists():
        raise RuntimeError(f"SE_EPHE_PATH does not exist: {ephe_path}")

    swe.set_ephe_path(str(ephe_path))

    global _EPHE_VALIDATED
    if not _EPHE_VALIDATED:
        missing = [name for name in REQUIRED_EPHE_FILES if not (ephe_path / name).exists()]
        if missing:
            missing_list = ", ".join(sorted(missing))
            raise RuntimeError(f"Missing Swiss Ephemeris data files: {missing_list}")
        _EPHE_VALIDATED = True

    return ephe_path


def _calc_body(jd: float, body_id: int, name: str) -> dict:
    flags = swe.FLG_SWIEPH | swe.FLG_SPEED
    try:
        xx, _ = swe.calc_ut(jd, body_id, flags)
    except Exception as exc:
        raise RuntimeError(f"calc_failed:{name}") from exc

    lon = _normalize_deg(float(xx[0]))
    lat = float(xx[1])
    speed = float(xx[3]) if len(xx) > 3 else 0.0
    sign, deg_in_sign = _sign_info(lon)
    return {
        "lon": lon,
        "lat": lat,
        "speed": speed,
        "retrograde": speed < 0,
        "sign": sign,
        "deg_in_sign": deg_in_sign,
    }


def _calc_obliquity(jd: float) -> float:
    try:
        xx, _ = swe.calc_ut(jd, swe.ECL_NUT)
        return float(xx[0])
    except Exception as exc:
        raise RuntimeError("obliquity_calc_failed") from exc


def _calc_houses(
    jd: float,
    lat: float,
    lon: float,
    house_system: str,
) -> Tuple[Dict[str, float], float, float, float, bytes]:
    hsys = HOUSE_SYSTEM_MAP.get(house_system, "P")
    hsys_code = hsys.encode("ascii")

    try:
        cusps_list, ascmc = swe.houses(jd, lat, lon, hsys_code)
    except Exception as exc:
        raise RuntimeError("houses_calc_failed") from exc

from __future__ import annotations

import json
import os
import subprocess
import sys
import time
from datetime import datetime, timezone
from pathlib import Path
from urllib.error import HTTPError, URLError
from urllib.request import Request, urlopen


def _env_str(name: str, default: str) -> str:
    value = os.getenv(name)
    return value if value else default


def _env_int(name: str, default: int) -> int:
    value = os.getenv(name)
    if not value:
        return default
    try:
        return int(value)
    except ValueError:
        return default


def _env_float(name: str, default: float) -> float:
    value = os.getenv(name)
    if not value:
        return default
    try:
        return float(value)
    except ValueError:
        return default


def _http_json(method: str, url: str, payload: dict | None = None, timeout: float = 10.0) -> dict:
    data = None
    headers = {"Accept": "application/json"}
    if payload is not None:
        data = json.dumps(payload).encode("utf-8")
        headers["Content-Type"] = "application/json"
    req = Request(url, data=data, headers=headers, method=method)
    with urlopen(req, timeout=timeout) as response:
        body = response.read().decode("utf-8")
        return json.loads(body)


def _wait_for_health(base_url: str, timeout_s: float) -> bool:
    deadline = time.time() + timeout_s
    url = f"{base_url}/v1/health"
    while time.time() < deadline:
        try:
            _http_json("GET", url, timeout=3.0)
            return True
        except (HTTPError, URLError, json.JSONDecodeError):
            time.sleep(0.5)
    return False


def _validate_envelope(obj: dict) -> tuple[bool, str]:
    required = {"meta", "settings", "input_summary", "data", "timing", "errors"}
    if set(obj.keys()) != required:
        return False, f"top-level keys mismatch: {sorted(obj.keys())}"
    errors = obj.get("errors")
    if not isinstance(errors, list):
        return False, "errors is not a list"
    if errors:
        return False, f"errors not empty: {errors}"
    return True, "ok"


def main() -> int:
    host = _env_str("SMOKE_HOST", "127.0.0.1")
    port = _env_int("SMOKE_PORT", 8000)
    timeout_s = _env_float("SMOKE_TIMEOUT", 30.0)
    base_url = f"http://{host}:{port}"

    repo_root = Path(__file__).resolve().parents[3]
    output_dir = repo_root / "SPIN" / "_logs" / "samples" / datetime.now(timezone.utc).strftime("%Y-%m-%d_%H%M%S")
    output_dir.mkdir(parents=True, exist_ok=True)
    log_path = output_dir / "uvicorn.log"

    api_root = Path(__file__).resolve().parents[1]
    env = os.environ.copy()
    env["PYTHONPATH"] = str(api_root)

    with open(log_path, "w", encoding="utf-8") as log_file:
        process = subprocess.Popen(
            [sys.executable, "-m", "uvicorn", "app.main:app", "--host", host, "--port", str(port)],
            cwd=api_root,
            env=env,
            stdout=log_file,
            stderr=subprocess.STDOUT,
        )

    try:
        if not _wait_for_health(base_url, timeout_s):
            print("Health check failed: timeout waiting for /v1/health")
            return 1

        base_location = {"lat": 40.7128, "lon": -74.0060, "alt_m": 10, "place": "NYC"}
        chart_req = {
            "metadata": {
                "chart_type": "natal",
                "timestamp_utc": "2024-01-01T00:00:00Z",
                "location": base_location,
                "client_name": "Test",
            },
            "settings": {
                "house_system": "placidus",
                "zodiac": "tropical",
                "coordinate_system": "ecliptic",
            },
        }

        transit_req = {
            "metadata": {
                "transit_type": "transit",
                "timestamp_utc": "2024-01-02T00:00:00Z",
                "location": base_location,
            },
            "frame_a": {
                "metadata": {
                    "chart_type": "natal",
                    "timestamp_utc": "2000-01-01T00:00:00Z",
                    "location": base_location,
                },
                "settings": {
                    "house_system": "placidus",
                    "zodiac": "tropical",
                    "coordinate_system": "ecliptic",
                },
            },
            "frame_b": {
                "metadata": {
                    "chart_type": "moment",
                    "timestamp_utc": "2024-01-02T00:00:00Z",
                    "location": base_location,
                },
                "settings": {
                    "house_system": "placidus",
                    "zodiac": "tropical",
                    "coordinate_system": "ecliptic",
                },
            },
        }

        timeline_req = {
            "metadata": {
                "start_utc": "2024-01-01T00:00:00Z",
                "end_utc": "2024-02-01T00:00:00Z",
                "bodies": ["uranus", "neptune", "pluto"],
            },
            "frame_a": {
                "metadata": {
                    "chart_type": "natal",
                    "timestamp_utc": "2000-01-01T00:00:00Z",
                    "location": base_location,
                },
                "settings": {
                    "house_system": "placidus",
                    "zodiac": "tropical",
                    "coordinate_system": "ecliptic",
                },
            },
        }

        progression_req = {
            "metadata": {
                "start_utc": "2024-01-01T00:00:00Z",
                "end_utc": "2024-02-01T00:00:00Z",
                "timeline_type": "secondary_progression",
            },
            "frame_a": {
                "metadata": {
                    "chart_type": "natal",
                    "timestamp_utc": "2000-01-01T00:00:00Z",
                    "location": base_location,
                },
                "settings": {
                    "house_system": "placidus",
                    "zodiac": "tropical",
                    "coordinate_system": "ecliptic",
                },
            },
        }

        requests = [
            ("health", "GET", "/v1/health", None),
            ("config", "GET", "/v1/config", None),
            ("chart", "POST", "/v1/chart", chart_req),
            ("transit", "POST", "/v1/transit", transit_req),
            ("timeline", "POST", "/v1/timeline", timeline_req),
            ("progression_timeline", "POST", "/v1/timeline", progression_req),
        ]

        failures: list[str] = []
        for name, method, path, payload in requests:
            url = f"{base_url}{path}"
            try:
                response = _http_json(method, url, payload=payload, timeout=30.0)
            except (HTTPError, URLError, json.JSONDecodeError) as exc:
                failures.append(f"{name}: request failed: {exc}")
                continue

            out_path = output_dir / f"{name}.json"
            out_path.write_text(json.dumps(response, indent=2, ensure_ascii=True), encoding="utf-8")

            ok, reason = _validate_envelope(response)
            if not ok:
                failures.append(f"{name}: {reason}")

        if failures:
            print("Smoke run failed:")
            for item in failures:
                print(f"- {item}")
            return 1

        print(f"Smoke run OK. Output: {output_dir}")
        return 0
    finally:
        if process.poll() is None:
            process.terminate()
            try:
                process.wait(timeout=5)
            except subprocess.TimeoutExpired:
                process.kill()


if __name__ == "__main__":
    raise SystemExit(main())

